t.script:

(function() {
"use strict";

const proyectoId = <t t-esc="proyecto.id" />;
const csrfToken  = "";

const inputBuscar   = document.getElementById("inputBuscarMiembro");
const divResultados = document.getElementById("resultadosMiembros");
const btnConfirmar  = document.getElementById("btnConfirmarMiembro");
const divNuevo      = document.getElementById("divNuevoMiembro");
const msgExito      = document.getElementById("msg-miembro-exito");
const msgError      = document.getElementById("msg-miembro-error");

let partnerId   = null;
let nombreNuevo = null;
let debounceTimer;

/**
 * Maneja la búsqueda de contactos para el equipo.
 * 
 * @private
 */
inputBuscar.addEventListener("input", function() {
    clearTimeout(debounceTimer);
    const term = this.value.trim();
    partnerId = null; 
    nombreNuevo = null;
    btnConfirmar.disabled = true;
    divResultados.innerHTML = "";
    divNuevo.classList.add("d-none");

    if (term.length < 2) {
        return;
    }

    debounceTimer = setTimeout(function() {
        fetch("/digitalizacion/api/v1/partners/search", {
            method: "POST",
            headers: { 
                "Content-Type": "application/json",
                "X-CSRF-Token": csrfToken
            },
            body: JSON.stringify({
                "jsonrpc": "2.0", 
                "method": "call", 
                "id": 1,
                "params": { 
                    "term": term, 
                    "proyecto_id": proyectoId 
                }
            })
        })
        .then(function(r) { return r.json(); })
        .then(function(response) {
            const data = response.result || {};
            const partners = data.data || [];
            divResultados.innerHTML = "";

            if (partners.length === 0) {
                nombreNuevo = term;
                divNuevo.classList.remove("d-none");
                btnConfirmar.disabled = false;
            } else {
                partners.forEach(function(p) {
                    const btn = document.createElement("button");
                    btn.className = "o_digitalizacion_result_item";
                    let label = p.name;
                    if (p.email) {
                        label += " (" + p.email + ")";
                    }
                    btn.textContent = label;
                    btn.addEventListener("click", function() {
                        partnerId = p.id; 
                        nombreNuevo = null;
                        inputBuscar.value = p.name;
                        divResultados.innerHTML = "";
                        divNuevo.classList.add("d-none");
                        btnConfirmar.disabled = false;
                        btn.classList.add("selected");
                    });
                    divResultados.appendChild(btn);
                });
            }
        })
        .catch(function() {
            divResultados.textContent = "Error al buscar contactos.";
        });
    }, 350);
});

/**
 * Confirma y agrega el miembro seleccionado al proyecto.
 * 
 * @private
 */
btnConfirmar.addEventListener("click", function() {
    btnConfirmar.disabled = true;
    fetch("/digitalizacion/api/v1/proyectos/" + proyectoId + "/miembros", {
        method: "POST",
        headers: { 
            "Content-Type": "application/json",
            "X-CSRF-Token": csrfToken
        },
        body: JSON.stringify({
            "jsonrpc": "2.0", 
            "method": "call", 
            "id": 1,
            "params": {
                "proyecto_id": proyectoId,
                "partner_id":  partnerId   || null,
                "nombre_nuevo": nombreNuevo || null
            }
        })
    })
    .then(function(r) { return r.json(); })
    .then(function(data) {
        const result = data.result || {};
        try {
            if (window.bootstrap) {
                const modal = window.bootstrap.Modal.getInstance(document.getElementById("modalAgregarMiembro"));
                if (modal) {
                    modal.hide();
                }
            } else {
                const m = document.getElementById("modalAgregarMiembro");
                m.classList.remove("show");
                m.style.display = "none";
                document.body.classList.remove("modal-open");
                const backdrop = document.querySelector(".modal-backdrop");
                if (backdrop) {
                    backdrop.remove();
                }
            }
        } catch(e) {
            console.warn(e);
        }
        if (result.success) {
            msgExito.classList.remove("d-none");
            msgError.classList.add("d-none");
            setTimeout(function() { 
                location.reload(); 
            }, 800);
        } else {
            const errObj = result.error || {};
            const errMsg = errObj.message || "Error al agregar miembro.";
            msgError.textContent = errMsg;
            msgError.classList.remove("d-none");
            msgExito.classList.add("d-none");
            btnConfirmar.disabled = false;
        }
    })
    .catch(function(err) {
        msgError.textContent = "Error de conexión / JS: " + (err ? err.message : "Desconocido");
        msgError.classList.remove("d-none");
        btnConfirmar.disabled = false;
    });
});

/**
 * Limpia el modal al cerrarse.
 * 
 * @private
 */
document.getElementById("modalAgregarMiembro")
    .addEventListener("hidden.bs.modal", function() {
        inputBuscar.value = "";
        divResultados.innerHTML = "";
        divNuevo.classList.add("d-none");
        btnConfirmar.disabled = true;
        partnerId = null; 
        nombreNuevo = null;
    });
})();
